const FutoroCogs = (
  <svg id="FutoroCogs" xmlns="http://www.w3.org/2000/svg" viewBox="-10 -10 720.000000 720.000000">
    <defs>
      {halfSaturateFilter}
      {smallestTopLeftCog}
      {bigCentralCog}
      {bottomRightCog}
    </defs>

    {/* Bottom right cog */}
    <use
      /* @ts-expect-error: see notes above */
      transformOrigin="508 508"
      href="#bottomRightCog"
      fill="currentColor"
      stroke="gray"
      strokeWidth={4}
      opacity={0.9}
    >
      <animateTransform
        attributeName="transform"
        type="rotate"
        from="0"
        to="360"
        dur="30s"
        repeatCount="indefinite"
      />
    </use>

    {/* Big middle cog */}
    <use
      /* @ts-expect-error: see notes above */
      transformOrigin="350 350"
      href="#bigCentralCog"
      fill="currentColor"
      stroke="lightgray"
      strokeWidth={2}
      filter="url(#halfSaturate)"
      opacity={0.7}
    >
      <animateTransform
        attributeName="transform"
        type="rotate"
        from="360"
        to="-0"
        dur="50s"
        repeatCount="indefinite"
      />
    </use>

    {/* Top left cog */}
    <use
      /* @ts-expect-error: see notes above */
      transformOrigin="125 125"
      href="#smallestTopLeftCog"
      fill="currentColor"
      stroke="gray"
      strokeWidth={4}
      opacity={0.7}
    >
      <animateTransform
        attributeName="transform"
        type="rotate"
        from="0"
        to="360"
        dur="5s"
        repeatCount="indefinite"
      />
    </use>
  </svg>
);

interface PoweredByFutoroProps {
  linkColor?: string;
  cogsColor?: string;
  poweredByTextColor?: string;
  futoroColor?: string;
}

export function PoweredByFutoro({
  linkColor = '#a01caf',
  cogsColor = '#a01caf',
  poweredByTextColor = '#808080',
  futoroColor = '#a01caf',
}: PoweredByFutoroProps) {
  return (
    <Link
      href="https://futoro.co.uk"
      target="_blank"
      rel="noopener noreferrer"
      className={cn(
        'inline-flex items-center gap-2 text-base transition-opacity hover:opacity-80 md:text-xl'
      )}
      style={{ color: linkColor }}
    >
      <span className="h-6 w-6 md:h-8 md:w-8" style={{ color: cogsColor }}>
        {FutoroCogs}
      </span>
      <span>
        <span style={{ color: poweredByTextColor }}>Powered by </span>
        <span style={{ color: futoroColor }}>Futoro</span>
      </span>
    </Link>
  );
}

interface FutoroLinkProps {
  href: string;
}

export function FutoroLink({ href }: FutoroLinkProps) {
  return (
    <Link
      href={href}
      className="w-48 h-48 lg:w-80 lg:h-80 text-primary hover:text-secondary transition-colors duration-300 inline-flex items-center justify-center"
    >
      {FutoroCogs}
    </Link>
  );
}

export default FutoroCogs;
export { smallestTopLeftCog, bottomRightCog, bigCentralCog };
